});

router.post("/events/bulk", async (req, res) => {
  const { ids, action } = req.body;
  if (!Array.isArray(ids) || !action) return res.status(400).json({ error: "Parametri non validi" });

  if (action === "approve") {
    await db.update(eventsTable).set({ status: "approved" }).where(inArray(eventsTable.id, ids));
  } else if (action === "reject") {
    await db.update(eventsTable).set({ status: "rejected" }).where(inArray(eventsTable.id, ids));
  } else if (action === "include_newsletter") {
    await db.update(eventsTable).set({ includedInNewsletter: true }).where(inArray(eventsTable.id, ids));
  } else {
    return res.status(400).json({ error: "Azione non valida" });
  }

  res.json({ message: `Azione eseguita su ${ids.length} eventi` });
});

router.post("/events/extract-screenshot", async (req, res) => {
  const { images, sourceUrl } = req.body;
  if (!Array.isArray(images) || !images.length) return res.status(400).json({ error: "Immagini richieste" });
  const fields = await claudeExtractFromImages(images);
  res.json({ ...fields, sourceUrl: sourceUrl || fields.source_url, dateParseConfidence: (fields as any).date_parse_confidence || "medium", recurring: false });
});

